import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from '../api';
import '../App.css';

const AdminLogin = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: '',
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // Direct login - NO OTP
      const response = await API.post('/auth/admin/login', formData);

      if (response.data.success) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('adminUser', JSON.stringify(response.data.admin));
        
        alert('Admin login successful!');
        navigate('/admin/dashboard');
      }
    } catch (error) {
      console.error('Admin login error:', error.response?.data);
      alert(error.response?.data?.message || 'Admin login failed.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page" style={{ background: 'linear-gradient(135deg, #434343 0%, #000000 100%)' }}>
      <div className="login-container">
        <div style={styles.adminBadge}>
          <span style={styles.crownIcon}>👑</span> ADMIN PORTAL
        </div>
        <h2>KDMC Administrator Login</h2>
        
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Admin Email</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="Enter admin email"
              required
            />
          </div>
          
          <div className="form-group">
            <label>Password</label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              placeholder="Enter password"
              required
            />
          </div>
          
          <button 
            type="submit" 
            className="login-btn" 
            disabled={loading}
            style={{ background: 'linear-gradient(135deg, #434343 0%, #000000 100%)' }}
          >
            {loading ? 'Logging in...' : 'Secure Login'}
          </button>
        </form>
        
        <p className="auth-footer">
          <Link to="/login">← Back to Citizen Login</Link>
        </p>
        
        <div style={styles.securityFooter}>
          <p style={styles.securityText}>
            🛡️ This is a secure admin portal. All login attempts are monitored.
          </p>
        </div>
      </div>
    </div>
  );
};

const styles = {
  adminBadge: {
    background: 'linear-gradient(135deg, #ff9800 0%, #f57c00 100%)',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '25px',
    textAlign: 'center',
    fontWeight: 'bold',
    fontSize: '14px',
    marginBottom: '20px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px'
  },
  crownIcon: {
    fontSize: '18px'
  },
  securityFooter: {
    marginTop: '20px',
    paddingTop: '15px',
    borderTop: '1px solid #f0f0f0'
  },
  securityText: {
    color: '#999',
    fontSize: '11px',
    textAlign: 'center',
    lineHeight: '1.5'
  }
};

export default AdminLogin;
